import axios from "axios";

const AUTH_API = axios.create({
  baseURL: "http://localhost:5000/api/auth",
  headers: { "Content-Type": "application/json" },
  timeout: 10000,
});

const OTP_API = axios.create({
  baseURL: "http://localhost:5000/api/otp",
  headers: { "Content-Type": "application/json" },
  timeout: 10000,
});

const RIDER_API = axios.create({
  baseURL: "http://localhost:5000/api/rider",
  headers: { "Content-Type": "application/json" },
  timeout: 10000,
});

// 🔹 User Auth APIs
export const signupUser = (formData) => AUTH_API.post("/signup-user", formData);
export const loginUser = (formData) => AUTH_API.post("/login-user", formData);

// 🔹 Rider Auth APIs
export const signupRider = (formData) => AUTH_API.post("/signup-rider", formData);
export const loginRider = (formData) => AUTH_API.post("/login-rider", formData);

// 🔹 OTP APIs (shared for both)
export const sendOtp = (mobile) => OTP_API.post("/send", { mobile });
export const verifyOtp = (mobile, otp) => OTP_API.post("/verify", { mobile, otp });

// 🔹 Rider-specific APIs
export const getRiderStatus = (token) =>
  RIDER_API.get("/status", { headers: { Authorization: `Bearer ${token}` } });

export const uploadRiderDocs = (token, docs) =>
  RIDER_API.post("/upload-docs", docs, {
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "multipart/form-data", // ✅ force multipart
    },
  });

// ✅ Keep backward compatibility (but recommend using role-specific ones)
export default {
  signupUser,
  signupRider,
  loginUser,
  loginRider,
  sendOtp,
  verifyOtp,
  getRiderStatus,
  uploadRiderDocs,
};
